{
    $callable = $this->action['uses'];

    if ($this->isSerializedClosure()) {
        $callable = unserialize($this->action['uses'], ['allowed_classes' => [
            SerializableClosure::class,
            \Laravel\SerializableClosure\UnsignedSerializableClosure::class,
