202	                    } elseif (! is_object($pipe)) {
203	                        [$name, $parameters] = $this->parsePipeString($pipe);
204	
205	                        // If the pipe is a string we will parse the string and resolve the class out
206	                        // of the dependency injection container. We can then build a callable and
207	                        // execute the pipe function giving in the parameters that are required.
208	                        $pipe = $this->getContainer()->make($name);
