73	     * @param  object  $skippableValue
74	     * @return mixed
75	     */
76	    protected function transformDependency(ReflectionParameter $parameter, $parameters, $skippableValue)
77	    {
78	        if ($attribute = Util::getContextualAttributeFromDependency($parameter)) {
79	            return $this->container->resolveFromAttribute($attribute, $parameter);
80	        }
81	
82	        $className = Reflector::getParameterClassName($parameter);
83	
84	        // If the parameter has a type-hinted class, we will check to see if it is already in
85	        // the list of parameters. If it is we will just skip it as it is probably a model
86	        // binding and we do not want to mess with those; otherwise, we resolve it here.
87	        if ($className && ! $this->alreadyInParameters($className, $parameters)) {
88	            $isEnum = (new ReflectionClass($className))->isEnum();
89	
90	            return $parameter->isDefaultValueAvailable()
91	                ? ($isEnum ? $parameter->getDefaultValue() : null)
92	                : $this->container->make($className);
93	        }
