18	abstract class AbstractRouteCollection implements Countable, IteratorAggregate, RouteCollectionInterface
19	{
20	    /**
21	     * Handle the matched route.
22	     *
23	     * @param  \Illuminate\Http\Request  $request
24	     * @param  \Illuminate\Routing\Route|null  $route
25	     * @return \Illuminate\Routing\Route
26	     *
27	     * @throws \Symfony\Component\HttpKernel\Exception\NotFoundHttpException
28	     */
29	    protected function handleMatchedRoute(Request $request, $route)
30	    {
31	        if (! is_null($route)) {
32	            return $route->bind($request);
33	        }
34	
35	        // If no route was found we will now check if a matching route is specified by
36	        // another HTTP verb. If it is we will need to throw a MethodNotAllowed and
37	        // inform the user agent of which HTTP verb it should use for this route.
38	        $others = $this->checkForAlternateVerbs($request);
39	
40	        if (count($others) > 0) {
41	            return $this->getRouteForMethods($request, $others);
42	        }
43	
44	        throw new NotFoundHttpException(sprintf(
45	            'The route %s could not be found.',
46	            $request->path()
47	        ));
48	    }
49	
50	    /**
51	     * Determine if any routes match on another HTTP verb.
52	     *
53	     * @param  \Illuminate\Http\Request  $request
54	     * @return array
55	     */
56	    protected function checkForAlternateVerbs($request)
57	    {
58	        $methods = array_diff(Router::$verbs, [$request->getMethod()]);
59	
60	        // Here we will spin through all verbs except for the current request verb and
61	        // check to see if any routes respond to them. If they do, we will return a
62	        // proper error response with the correct headers on the response string.
63	        return array_values(array_filter(
